import boto3
import sys

def create_sns_subscriptions(topic_arn, endpoints):
    sns = boto3.client('sns')
    
    for endpoint in endpoints:
        try:
            response = sns.subscribe(
                TopicArn=topic_arn,
                Protocol='https',
                Endpoint=endpoint
            )
            print(f"Subscription created: {response['SubscriptionArn']}")
        except Exception as e:
            print(f"Failed to subscribe {endpoint}: {str(e)}")

